                        playerSource: typeof playerSource !== 'undefined' ? playerSource : 'other'
                    },
                    viewed: {
                        threshold : 60, // Poking the server after 60 seconds to track if user stayed at least one minute
                        url: flashvars.viewedRequestURL
                    },
